250→export const useFollowMutation = (session, followingId) =>{
251→    const queryClient = useQueryClient();
252→    const queryFilter = {
253→        queryKey: ['followsData'],
254→        predicate: (query) => query.queryKey[2] === followingId,
255→    };
256→
257→    return useMutation({
258→        mutationFn: (data) => addFollows(data, session?.access_token),
259→
260→        onMutate: async() => {
261→            await queryClient.cancelQueries(queryFilter);
262→            const allMatching = queryClient.getQueriesData(queryFilter);
263→
264→            queryClient.setQueriesData(queryFilter, (old) => {
265→                if(!old) return old;
266→                return{
267→                    ...old,
268→                    followersCount: old.isFollowing ? old.followersCount - 1 : old.followersCount + 1,
269→                    isFollowing: !old.isFollowing
270→                }
271→            })
272→
273→            return {allMatching};
274→
275→        },
276→        onError: (_err, _data, context) => {
277→            context?.allMatching?.forEach(([key, data]) => {
278→                queryClient.setQueryData(key, data);
279→            });
280→        },
281→        onSettled: () => {
282→            queryClient.invalidateQueries({ queryKey: ['followsData'] });
283→        }
284→    })
285→}
