287→export const useReadNotificationMutation = (session) =>{
288→    const queryClient = useQueryClient();
289→    return useMutation({
290→        mutationFn: (data) => readNotification(session?.access_token, data?.notifId, data?.source),
291→        onMutate: async(data) => {
292→            await queryClient.cancelQueries(['notifcounts', session?.user?.id]);
293→            const previousData = queryClient.getQueryData(['notifcounts', session?.user?.id])
294→
295→            queryClient.setQueryData(['notifcounts', session?.user?.id], (old) => ({count: (old?.count ? old?.count : 0) - 1}));
296→
297→            return{previousData};
298→        },
299→         onError: (err, data, context) => {
300→            queryClient.setQueryData(['notifcounts', session?.user?.id], context.previousData)
301→         },
302→         onSettled: () => {
303→            queryClient.invalidateQueries(['notifcounts', session?.user?.id]);
304→         }
305→    })
306→}
